blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie zobaczysz, jak tworzyć stronę bierną z <strong>czasownikami frazowymi</strong>. Najważniejsza zasada jest prosta: <strong>cząstka albo przyimek zostaje przy czasowniku</strong>.",
    "rules": [
        {
            "label": "Active",
            "color": "emerald",
            "text": "W stronie czynnej mamy układ <strong>subject + phrasal verb + object</strong>.",
            "example": "They called off the meeting."
        },
        {
            "label": "Passive",
            "color": "blue",
            "text": "W stronie biernej używamy układu <strong>object + be + V3 + particle / preposition</strong>.",
            "example": "The meeting was called off."
        },
        {
            "label": "Najważniejsza zasada",
            "color": "rose",
            "text": "Cząstki nie odrywamy od czasownika.",
            "example": "The baby was looked after. ✅"
        }
    ]
}

{
    "title": "1. Typowe czasowniki frazowe w stronie biernej",
    "intro": "Najczęściej używane czasowniki frazowe w stronie biernej:",
    "items": [
        {
            "label": "opiekować się",
            "title": "pielęgnacja",
            "subtitle": "Dzieci mają dobrą opiekę."
        },
        {
            "label": "wychować",
            "title": "kształcić",
            "subtitle": "Wychowała ją babcia."
        },
        {
            "label": "odwołać",
            "title": "anulować",
            "subtitle": "Mecz został odwołany."
        },
        {
            "label": "budzić wstręt",
            "title": "odłożyć",
            "subtitle": "Spotkanie przełożono na poniedziałek."
        },
        {
            "label": "odrzucać",
            "title": "odrzucić",
            "subtitle": "Jego oferta została odrzucona."
        },
        {
            "label": "przeprowadzać coś",
            "title": "dokonywać",
            "subtitle": "Eksperyment został przeprowadzony."
        },
        {
            "label": "zbadać",
            "title": "zbadać",
            "subtitle": "Sprawa jest badana."
        },
        {
            "label": "włamać się",
            "title": "włamać się",
            "subtitle": "Włamano się do domu."
        }
    ]
}

{
    "title": "2. Porównanie trybu aktywnego i pasywnego",
    "intro": "Transformacja czasowników frazowych z strony czynnej na bierną:",
    "rows": [
        {
            "en": "Active: They called off the game.",
            "ua": "Anulowali mecz.",
            "note": "→ Passive: The game was called off."
        },
        {
            "en": "Active: Someone broke into the car.",
            "ua": "Ktoś włamał się do samochodu.",
            "note": "→ Passive: The car was broken into."
        },
        {
            "en": "Active: They are looking into the problem.",
            "ua": "Badają problem.",
            "note": "→ Passive: The problem is being looked into."
        },
        {
            "en": "Active: Her grandparents brought her up.",
            "ua": "Wychowywali ją dziadkowie.",
            "note": "→ Passive: She was brought up by her grandparents."
        }
    ],
    "warning": "📌 Imiesłów/przyimek ZAWSZE pozostaje z czasownikiem!"
}

{
    "title": "3. Czasowniki frazowe w stronie biernej według kategorii",
    "sections": [
        {
            "label": "Anulowanie/przełożenie",
            "color": "rose",
            "description": "odwołać, odłożyć, anulować:",
            "examples": [
                {
                    "en": "The concert was called off due to rain.",
                    "ua": "Koncert został odwołany z powodu deszczu."
                },
                {
                    "en": "The meeting has been put off.",
                    "ua": "Spotkanie zostało przełożone."
                },
                {
                    "en": "The flight was put off until tomorrow.",
                    "ua": "Lot został przełożony na jutro."
                }
            ]
        },
        {
            "label": "Wdrożenie / wdrożenie",
            "color": "emerald",
            "description": "przeprowadzić, doprowadzić, ustanowić:",
            "examples": [
                {
                    "en": "The research was carried out last year.",
                    "ua": "Badania przeprowadzono w ubiegłym roku."
                },
                {
                    "en": "Major changes were brought about.",
                    "ua": "Wprowadzono istotne zmiany."
                },
                {
                    "en": "A new company was set up.",
                    "ua": "Powstała nowa firma."
                }
            ]
        },
        {
            "label": "Odrzucenie / odmowa",
            "color": "blue",
            "description": "odrzucić, wykluczyć, wyrzucić:",
            "examples": [
                {
                    "en": "Her application was turned down.",
                    "ua": "Jej wniosek został odrzucony."
                },
                {
                    "en": "This option cannot be ruled out.",
                    "ua": "Nie można wykluczyć tej opcji."
                },
                {
                    "en": "The proposal was thrown out.",
                    "ua": "Propozycja została odrzucona."
                }
            ]
        },
        {
            "label": "Opieka / wychowanie",
            "color": "amber",
            "description": "opiekować się, wychowywać, opiekować się:",
            "examples": [
                {
                    "en": "The patient is being looked after.",
                    "ua": "Pacjent jest objęty opieką."
                },
                {
                    "en": "He was brought up in a small village.",
                    "ua": "Dorastał w małej wiosce."
                },
                {
                    "en": "Everything will be taken care of.",
                    "ua": "Wszystko zostanie załatwione."
                }
            ]
        }
    ]
}

{
    "title":  "4. Czasowniki frazowe w stronie biernej: różne czasy",
    "sections":  [
                     {
                         "label":  "Czas teraźniejszy prosty",
                         "color":  "emerald",
                         "description":  "\u003cstrong\u003eam / is / are + V3 + particle / preposition\u003c/strong\u003e",
                         "examples":  [
                                          {
                                              "en":  "Children are looked after at the nursery.",
                                              "ua":  "Dzieci objęte są opieką w przedszkolu."
                                          },
                                          {
                                              "en":  "Problems are dealt with quickly.",
                                              "ua":  "Problemy są rozwiązywane szybko."
                                          }
                                      ]
                     },
                     {
                         "label":  "Czas przeszły prosty",
                         "color":  "blue",
                         "description":  "\u003cstrong\u003ewas / were + V3 + particle / preposition\u003c/strong\u003e",
                         "examples":  [
                                          {
                                              "en":  "The project was carried out successfully.",
                                              "ua":  "Projekt został pomyślnie ukończony."
                                          },
                                          {
                                              "en":  "The meeting was called off yesterday.",
                                              "ua":  "Wczorajsze spotkanie zostało odwołane."
                                          }
                                      ]
                     },
                     {
                         "label":  "Czas teraźniejszy idealny",
                         "color":  "amber",
                         "description":  "\u003cstrong\u003ehas / have been + V3 + particle / preposition\u003c/strong\u003e",
                         "examples":  [
                                          {
                                              "en":  "The event has been put off.",
                                              "ua":  "Wydarzenie zostało przełożone."
                                          },
                                          {
                                              "en":  "His idea has been turned down.",
                                              "ua":  "Jego pomysł został odrzucony."
                                          }
                                      ]
                     },
                     {
                         "label":  "Czas teraźniejszy ciągły",
                         "color":  "rose",
                         "description":  "\u003cstrong\u003eam / is / are being + V3 + particle / preposition\u003c/strong\u003e",
                         "examples":  [
                                          {
                                              "en":  "The matter is being looked into.",
                                              "ua":  "Sprawa jest badana."
                                          },
                                          {
                                              "en":  "New measures are being brought in.",
                                              "ua":  "Wdrażane są nowe środki."
                                          }
                                      ]
                     }
                 ]
}

{
    "title": "5. Czasowniki z przyimkami w stronie biernej",
    "intro": "Czasowniki z przyimkami stałymi również tworzą stronę bierną:",
    "items": [
        {
            "label": "śmiać się",
            "title": "śmiać się z",
            "subtitle": "Nienawidzi, jak się z niego śmieje."
        },
        {
            "label": "przyglądać się",
            "title": "przyglądać się",
            "subtitle": "Trwa oglądanie obrazu."
        },
        {
            "label": "porozmawiać",
            "title": "porozmawiać",
            "subtitle": "Nie lubię, jak się do mnie tak mówi."
        },
        {
            "label": "odnieść się do",
            "title": "odnieść się do",
            "subtitle": "Często wspomina się o tej książce."
        },
        {
            "label": "polegać",
            "title": "polegać",
            "subtitle": "Można na nim polegać."
        },
        {
            "label": "radzić sobie z",
            "title": "sobie poradzić",
            "subtitle": "Problem jest w trakcie rozwiązywania."
        }
    ]
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Oddzielenie imiesłowu od czasownika.",
            "wrong": "The baby was looked well after.",
            "right": "✅ The baby was looked after well."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Pominięcie imiesłowu/przyimka.",
            "wrong": "The meeting was called.",
            "right": "✅ The meeting was called off."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Nieprawidłowy przyimek.",
            "wrong": "He was laughed on by everyone.",
            "right": "✅ He was laughed at by everyone."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Nieprawidłowa kolejność słów w by.",
            "wrong": "The child was by her aunt brought up.",
            "right": "✅ The child was brought up by her aunt."
        }
    ]
}
